export class FileUploadDialogComponent {
  faUpload = faUpload;
  faFile = faFileAlt;
  faTrash = faTrash;
  
  selectedFiles: File[] = [];
  isLoading = false;

  constructor(
    private _snackBar: MatSnackBar,
    public dialogRef: MatDialogRef<FileUploadDialogComponent>,
    private itemService: itemService,
    private helperService: HelperService,
    @Inject(MAT_DIALOG_DATA) public data: { 
      itemId: number, 
      value: string,
      files?: File[]  // Optional pre-selected files
    }
  ) {
    // If files are passed in data, add them
    if (this.data?.files) {
      this.selectedFiles = [...this.data.files];
    }
  }

  onFileChange(event: any) {
    const files = Array.from(event.target.files) as File[];
    this.selectedFiles = [...this.selectedFiles, ...files];
  }

  onDrop(event: DragEvent) {
    event.preventDefault();
    if (event.dataTransfer?.files) {
      const files = Array.from(event.dataTransfer.files);
      this.selectedFiles = [...this.selectedFiles, ...files];
    }
  }

  allowDrop(event: DragEvent) {
    event.preventDefault();
  }

  removeFile(index: number) {
    this.selectedFiles.splice(index, 1);
  }

  onCancel() {
    this.dialogRef.close();
  }

  onSave() {
    if (this.isLoading) { return; }
    
    if (!this.selectedFiles.length) {
      this._snackBar.open("You need to choose file first!", 'Close', {
        duration: 2000,
      });
      return;
    }

    const file = this.selectedFiles[0];
    let contentType = file.type;
    const extension = file.name.split('.').pop().toLowerCase();
    let fileName;
    
    if (extension === 'ai') {
      fileName = `${new Date().getTime()}-${file.name.toLowerCase().replace('.ai', '.pdf')}`;
      contentType = 'application/pdf';
    } else if (['ai', 'pdf'].includes(extension)) {
      fileName = `${new Date().getTime()}-${file.name.toLowerCase()}`;
    } else {
      fileName = 'images-' + `${new Date().getTime()}-${file.name.toLowerCase()}`;
    }
    
    this.isLoading = true;
    
    this.itemService
      .getPreSignedUrl({ fileName, contentType })
      .pipe(take(1))
      .subscribe({
        next: (res: { signedUrl: string }) => {
        if (!res || !res.signedUrl) {
          this.isLoading = false;
          this._snackBar.open("Upload failed: could not get upload URL.", 'Close', {
            duration: 4000,
          });
          console.error('getPreSignedUrl returned an unexpected response:', res);
          return;
        }
        const signedUrl = res.signedUrl;
        const headers = new Headers({
          'Content-Type': contentType, 
          'x-amz-acl': 'public-read' 
        });
        
        const putConfig = { 
          method: 'PUT', 
          body: file, 
          headers: headers 
        };
        
        fetch(signedUrl, putConfig)
          .then(async output => {
            if (!output.ok) {
              throw new Error(`S3 upload failed with status ${output.status}`);
            }
            if (!this.data.itemId) {
              const sharedLink = this.helperService.buildPublicUrl(fileName);
              const thumbName = `thumbs-${fileName.replace('images-', '')}`;
              const thumbFile = await this.helperService.resizeImage(file, thumbName);
              await this.helperService.saveToDigitalOceanAndDB(thumbName, contentType, thumbFile);
              const thumbSharedLink = this.helperService.buildPublicUrl(thumbName);
              
              this.isLoading = false;
              return this.dialogRef.close({ sharedLink, thumbSharedLink });
            }
            
            const body = this.data.value === 'rfq'
              ? { flag: 'rfq-update', fileName }
              : {
                  flag: 'item-attachment-create',
                  item_num_id_fk: this.data.itemId,
                  attachment_type: contentType,
                  attachment_display_name: contentType.split("/")[0],
                  fileName
                };
            
            this.itemService
              .saveTechLink(body, this.data.itemId)
              .pipe(take(1))
              .subscribe({
                next: (res: { sharedLink: string }) => {
                  if (!res || !res.sharedLink) {
                    this.isLoading = false;
                    this._snackBar.open(
                      "Upload failed: the file was uploaded but could not be saved. Please try again.",
                      'Close',
                      { duration: 5000 }
                    );
                    console.error('saveTechLink returned an unexpected response:', res);
                    return;
                  }
                  this.isLoading = false;
                  this.dialogRef.close(res.sharedLink);
                },
                error: (error) => {
                  this.isLoading = false;
                  this._snackBar.open(
                    "Upload failed: the file was uploaded but could not be saved. Please try again.",
                    'Close',
                    { duration: 5000 }
                  );
                  console.error('saveTechLink error:', error);
                }
              });
          })
          .catch(error => {
            this.isLoading = false;
            this._snackBar.open("Upload failed!", 'Close', {
              duration: 2000,
            });
            console.error('Upload error:', error);
          });
        },
        error: (error) => {
          this.isLoading = false;
          this._snackBar.open("Upload failed: could not get upload URL.", 'Close', {
            duration: 4000,
          });
          console.error('getPreSignedUrl error:', error);
        }
      });
  }
}

