import { Injectable } from '@angular/core';
import { first } from 'rxjs/operators';
import { itemService } from './main.service';
import { ConfigService } from './config.service';

@Injectable({
  providedIn: 'root',
})
export class HelperService {
  constructor(
    private api: itemService,
    private configService: ConfigService
  ) {}

  public getDigitalOceanPublicURL(): string {
    return this.configService.DIGITAL_OCEAN_PUBLIC_URL;
  }

  public buildPublicUrl(fileNameOrUrl: string): string {
    if (!fileNameOrUrl) {
      return fileNameOrUrl;
    }

    const baseUrl = this.getDigitalOceanPublicURL().replace(/\/+$/, '');

    if (fileNameOrUrl.startsWith(`${baseUrl}/`)) {
      return fileNameOrUrl;
    }

    // Repair full URLs saved without a slash between host and path.
    if (fileNameOrUrl.startsWith(baseUrl)) {
      return this.buildPublicUrl(fileNameOrUrl.slice(baseUrl.length));
    }

    // Leave other absolute URLs (CDN placeholders, external links) unchanged.
    if (/^https?:\/\//i.test(fileNameOrUrl)) {
      return fileNameOrUrl;
    }

    const normalizedFileName = fileNameOrUrl.replace(/^\/+/, '');
    return `${baseUrl}/${normalizedFileName}`;
  }

  async saveToDigitalOceanAndDB(fileName: string, contentType: string, file: File): Promise<any> {
    const res: any = await this.api.getPreSignedUrl({ fileName, contentType }).pipe(first()).toPromise();
    const signedUrl = res.signedUrl;
    const headers = new Headers({ 'Content-Type': contentType, 'x-amz-acl': 'public-read' });
    const putConfig: any = { method: 'PUT', body: file, headers: headers };
    return fetch(signedUrl, putConfig);
  }

  resizeImage(file: File, fileName: string): Promise<File> {
    return new Promise(async (resolve) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = async () => {
        const image = new Image();
        image.onload = async function () {
          const canvas = document.createElement('canvas');
          canvas.width = 200;
          canvas.height = 200;
          const ctx = canvas.getContext('2d');
          if (ctx != null) {
            ctx.drawImage(image, 0, 0, 200,200);
          }
          const data = canvas.toDataURL('image/jpeg', 1);
          const response = await fetch(data);
          const blob = await response.blob();
          const file = new File([blob], fileName, { type: "image/jpeg" })
          resolve(file);
        };
        image.src = reader.result as string;
      }
    });
  }
}

