const mockRoutes = [];

jest.mock('express', () => ({
  Router: jest.fn(() => ({
    get: jest.fn((path, ...handlers) => mockRoutes.push({ method: 'get', path, handlers })),
    post: jest.fn((path, ...handlers) => mockRoutes.push({ method: 'post', path, handlers })),
    put: jest.fn((path, ...handlers) => mockRoutes.push({ method: 'put', path, handlers })),
  })),
}));

jest.mock('../../helpers/digitalocean', () => ({
  getListOfBuckets: jest.fn(),
  getBucketObjects: jest.fn(),
  setCORSForBucket: jest.fn(),
  getPreSignedUrl: jest.fn(),
  setObjectPublic: jest.fn(),
  deleteObjectsFromBucket: jest.fn(),
}));

jest.mock('../../helpers/multer', () => ({}));

jest.mock('../../config/digitalocean.config', () => ({
  PUBLIC_URL: 'https://cdn.example.com',
}));

jest.mock('../../models/lib.model.js', () => ({
  saveTechLink: jest.fn(),
}));

jest.mock('../../helpers/auth', () => ({
  authRole: jest.fn((roles) => {
    const middleware = jest.fn();
    middleware.authRoles = roles;
    return middleware;
  }),
}));

describe('digitalocean router auth', () => {
  beforeEach(() => {
    mockRoutes.length = 0;
    jest.resetModules();
  });

  test('blocks factory users from general upload and item attachment endpoints', () => {
    require('../../routes/digitalocean.router');

    const protectedUploadRoutes = [
      ['/getPreSignedUrl', 'post'],
      ['/setObjectPublic', 'post'],
      ['/saveTechLink/:id', 'post'],
      ['/deleteBucketObjects', 'post'],
    ];

    for (const [path, method] of protectedUploadRoutes) {
      const route = mockRoutes.find(entry => entry.method === method && entry.path === path);

      expect(route).toBeDefined();
      expect(route.handlers[0].authRoles).toEqual(['designer', 'sourcing_manager', 'sales', 'production']);
      expect(route.handlers[0].authRoles).not.toContain('vendor');
    }
  });
});

